// And groups predicates with the AND operator between them.
func And(predicates ...predicate.KnowledgeEntityAlias) predicate.KnowledgeEntityAlias {
	return predicate.KnowledgeEntityAlias(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.KnowledgeEntityAlias) predicate.KnowledgeEntityAlias {
	return predicate.KnowledgeEntityAlias(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.KnowledgeEntityAlias) predicate.KnowledgeEntityAlias {
	return predicate.KnowledgeEntityAlias(sql.NotPredicates(p))
}
